    {12491,"Direbrew's Dire Brew",-1,-370,{"emulator","wago"},"Coren Direbrew's corpse clutched this small cask tightly to its gut.  This must be his infamous Dire Brew!",nil,nil,{{itemID=37829,count=40}},65,0,nil,"Give Direbrew's Dire Brew to Ipfelkofer Ironkeg at the Brewfest camp near Ironforge.",0,nil,1101,nil,{24710}},
    {12492,"Direbrew's Dire Brew",-1,-370,{"emulator","wago"},"Coren Direbrew's corpse clutched this small cask tightly to its gut. This must be his infamous Dire Brew!",nil,nil,{{itemID=37829,count=40}},65,0,nil,"Give Direbrew's Dire Brew to Tapper Swindlekeg at the Brewfest camp near Orgrimmar.",0,nil,690,nil,{24711}},
